import{_ as a,o as e,c as i,an as t}from"./chunks/framework.ubcH7j8_.js";const k=JSON.parse('{"title":"Getting Started","description":"","frontmatter":{},"headers":[],"relativePath":"guide/getting-started.md","filePath":"guide/getting-started.md","lastUpdated":1773164166000}'),n={name:"guide/getting-started.md"};function l(h,s,p,r,o,c){return e(),i("div",null,[...s[0]||(s[0]=[t(`<h1 id="getting-started" tabindex="-1">Getting Started <a class="header-anchor" href="#getting-started" aria-label="Permalink to &quot;Getting Started&quot;">​</a></h1><p>This guide takes you from a fresh clone to a running A.R.C. Platform with verified service health.</p><h2 id="prerequisites" tabindex="-1">Prerequisites <a class="header-anchor" href="#prerequisites" aria-label="Permalink to &quot;Prerequisites&quot;">​</a></h2><p>Before you begin, install the following tools:</p><table tabindex="0"><thead><tr><th>Tool</th><th>Version</th><th>Purpose</th></tr></thead><tbody><tr><td><a href="https://docs.docker.com/get-docker/" target="_blank" rel="noreferrer">Docker</a></td><td>24+ (with Compose v2)</td><td>Container runtime for all platform services</td></tr><tr><td><a href="https://github.com/arc-framework/arc-cli" target="_blank" rel="noreferrer"><code>arc</code> CLI</a></td><td>latest</td><td>Workspace management and service orchestration</td></tr><tr><td><a href="https://cli.github.com/" target="_blank" rel="noreferrer"><code>gh</code> CLI</a></td><td>2.x</td><td>GitHub operations (required for <code>make publish-all</code>)</td></tr><tr><td><a href="https://nodejs.org/" target="_blank" rel="noreferrer">Node.js</a></td><td>18+</td><td>Only needed to run the docs site locally</td></tr></tbody></table><p>Verify your setup:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">docker</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --version</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">          # Docker version 24.x.x</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">docker</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> compose</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> version</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">    # Docker Compose version v2.x.x</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">arc</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> version</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">               # arc version vX.Y.Z</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">gh</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --version</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">              # gh version 2.x.x</span></span></code></pre></div><h2 id="fork-and-clone-the-repository" tabindex="-1">Fork and Clone the Repository <a class="header-anchor" href="#fork-and-clone-the-repository" aria-label="Permalink to &quot;Fork and Clone the Repository&quot;">​</a></h2><p>Fork the repository on GitHub, then clone your fork:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">gh</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> repo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> fork</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> arc-framework/arc-platform</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --clone</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --remote</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">cd</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> arc-platform</span></span></code></pre></div><p>This adds both <code>origin</code> (your fork) and <code>upstream</code> (arc-framework/arc-platform) as remotes.</p><p>If you want a direct clone without forking:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">git</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> clone</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> https://github.com/arc-framework/arc-platform.git</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">cd</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> arc-platform</span></span></code></pre></div><h2 id="initialize-the-workspace" tabindex="-1">Initialize the Workspace <a class="header-anchor" href="#initialize-the-workspace" aria-label="Permalink to &quot;Initialize the Workspace&quot;">​</a></h2><p>Run <code>arc workspace init</code> to create your <code>arc.yaml</code> manifest. This command prompts for a tier and writes the file to the repository root.</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">arc</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> workspace</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> init</span></span></code></pre></div><p>Example session:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>? Select a platform tier:</span></span>
<span class="line"><span>  &gt; think       — core infrastructure only, fastest to start</span></span>
<span class="line"><span>    reason      — core + reasoning engine (LLM)</span></span>
<span class="line"><span>    ultra-instinct — full platform, all capabilities</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Workspace initialized: arc.yaml</span></span></code></pre></div><p>You can also pass flags to skip the prompt:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">arc</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> workspace</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> init</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --tier</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> think</span></span></code></pre></div><p>The generated <code>arc.yaml</code> looks like this:</p><div class="language-yaml vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">yaml</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">version</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;1.0.0&quot;</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">tier</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;think&quot;</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">capabilities</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: []</span></span></code></pre></div><h2 id="start-the-platform" tabindex="-1">Start the Platform <a class="header-anchor" href="#start-the-platform" aria-label="Permalink to &quot;Start the Platform&quot;">​</a></h2><p>Start all services for the <code>think</code> tier with:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">arc</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> run</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --profile</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> think</span></span></code></pre></div><p>The CLI resolves services from <code>services/profiles.yaml</code>, renders a Docker Compose file, and calls <code>docker compose up</code> in detached mode. On first run, Docker pulls the required images — this may take a few minutes depending on your connection.</p><p>Expected output:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Starting arc-platform [think]</span></span>
<span class="line"><span>  core services: messaging, cache, streaming, cortex, persistence, gateway, friday-collector</span></span>
<span class="line"><span>Pulling images... done</span></span>
<span class="line"><span>Starting services... done</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Platform is ready.</span></span>
<span class="line"><span>  Gateway:    http://localhost:80</span></span>
<span class="line"><span>  Cortex API: http://localhost:8801/health</span></span></code></pre></div><h2 id="verify-service-health" tabindex="-1">Verify Service Health <a class="header-anchor" href="#verify-service-health" aria-label="Permalink to &quot;Verify Service Health&quot;">​</a></h2><p>Once the platform is up, confirm all services are healthy:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">make</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> dev-health</span></span></code></pre></div><p>Expected output (all services show <code>healthy</code>):</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>arc-gateway          healthy   http://localhost:8090/ping</span></span>
<span class="line"><span>arc-messaging        healthy   http://localhost:8222/healthz</span></span>
<span class="line"><span>arc-streaming        healthy   http://localhost:8082/admin/v2/brokers/health</span></span>
<span class="line"><span>arc-cache            healthy   (redis-cli ping → PONG)</span></span>
<span class="line"><span>arc-persistence      healthy   (pg_isready)</span></span>
<span class="line"><span>arc-cortex           healthy   http://localhost:8801/health</span></span>
<span class="line"><span>arc-friday-collector healthy   http://localhost:13133/</span></span></code></pre></div><p>If any service shows <code>unhealthy</code> or <code>starting</code>, wait 10–15 seconds and re-run <code>make dev-health</code>. Most services need a moment to complete their own startup sequences.</p><h2 id="stop-the-platform" tabindex="-1">Stop the Platform <a class="header-anchor" href="#stop-the-platform" aria-label="Permalink to &quot;Stop the Platform&quot;">​</a></h2><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">make</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> dev-down</span></span></code></pre></div><p>This stops and removes all containers started by the current profile. Persistent volumes are retained so your data survives restarts.</p><h2 id="next-steps" tabindex="-1">Next Steps <a class="header-anchor" href="#next-steps" aria-label="Permalink to &quot;Next Steps&quot;">​</a></h2><ul><li><a href="/arc-platform/docs/services/">Services</a> — ports, health URLs, and API references for every service</li><li><a href="/arc-platform/docs/contributing/architecture.html">Contributing</a> — architecture overview, conventions, and guides for adding new services and capabilities</li><li><a href="/arc-platform/docs/guide/llm-testing.html">LLM Testing</a> — <code>curl</code> examples for the reasoning engine and voice service</li><li><a href="/arc-platform/docs/guide/arc-yaml-reference.html">arc.yaml Reference</a> — full reference for the workspace manifest</li></ul><h2 id="troubleshooting" tabindex="-1">Troubleshooting <a class="header-anchor" href="#troubleshooting" aria-label="Permalink to &quot;Troubleshooting&quot;">​</a></h2><h3 id="docker-not-running" tabindex="-1">Docker not running <a class="header-anchor" href="#docker-not-running" aria-label="Permalink to &quot;Docker not running&quot;">​</a></h3><p>Make sure Docker Desktop is started and the whale icon appears in your system tray. Verify with:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">docker</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ps</span></span></code></pre></div><h3 id="port-conflict" tabindex="-1">Port conflict <a class="header-anchor" href="#port-conflict" aria-label="Permalink to &quot;Port conflict&quot;">​</a></h3><p>Another process is using a default port. Check which port is conflicting:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">lsof</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -i</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> :</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&lt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">POR</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">T</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&gt;</span></span></code></pre></div><p>Then stop the conflicting process or change the port in your service override.</p><h3 id="services-failing-health-checks" tabindex="-1">Services failing health checks <a class="header-anchor" href="#services-failing-health-checks" aria-label="Permalink to &quot;Services failing health checks&quot;">​</a></h3><p>Your machine may not have enough resources. Check with <code>docker stats</code>. Consider using the <code>think</code> profile (lightest) to start:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">arc</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> run</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --profile</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> think</span></span></code></pre></div><h3 id="symlink-issues-on-macos-apple-silicon" tabindex="-1">Symlink issues on macOS (Apple Silicon) <a class="header-anchor" href="#symlink-issues-on-macos-apple-silicon" aria-label="Permalink to &quot;Symlink issues on macOS (Apple Silicon)&quot;">​</a></h3><p>If <code>docs/specs</code> shows as broken, ensure you cloned with symlink support:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">git</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> config</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> core.symlinks</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> true</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">git</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> checkout</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> .</span></span></code></pre></div>`,53)])])}const g=a(n,[["render",l]]);export{k as __pageData,g as default};
